content.text:
Object methods are defined as functions within an object literal. Syntax:
```javascript
const object = {
  methodName: function() {
    return result;
  }
};
```
Alternatively, ES6 provides a shorter syntax:
```javascript
const object = {
  methodName() {
    return result;
  }
};
```
Methods can access the object's properties using the `this` keyword.

content.code:
// Defining an object method
const car = {
  brand: 'Honda',
  model: 'Civic',
  year: 2021,
  startEngine: function() {
    return this.brand + ' ' + this.model + ' engine started!';
  },
  // ES6 short syntax
  getInfo() {
    return 'Car: ' + this.brand + ', Year: ' + this.year;
  }
};

console.log(car.startEngine()); // Honda Civic engine started!
console.log(car.getInfo()); // Car: Honda, Year: 2021

// Using `this`
const person = {
  name: 'Aysu',
  age: 22,
  introduce: function() {
    return 'Hi, I am ' + this.name + ' and I am ' + this.age + ' years old.';
  }
};
console.log(person.introduce()); // Hi, I am Aysu and I am 22 years old.

content.text:
Methods can be added to an object after its creation, similar to adding properties. Syntax:
```javascript
object.newMethod = function() {
  return result;
};
```

content.code:
// Adding a method
const book = {
  title: 'JavaScript Basics',
  pages: 200
};

// Adding a new method
book.getSummary = function() {
  return this.title + ' has ' + this.pages + ' pages.';
};
console.log(book.getSummary()); // JavaScript Basics has 200 pages.

// Error-prone example
const student = {
  name: 'Ali',
  grade: 90,
  showGrade: function() {
    return this.name + ' got ' + this.grade;
  }
};

// Error: Method called in wrong context
const func = student.showGrade;
console.log(func()); // TypeError: Cannot read property 'name' of undefined

// Correct approach
console.log(student.showGrade()); // Ali got 90

// Error: Incorrect method name
console.log(student.showGrades); // undefined (showGrades doesn't exist)

// Method vs. function comparison
const person = {
  name: 'Veli',
  greet: function() {
    return 'Hello, ' + this.name;
  }
};

// Method call
console.log(person.greet()); // Hello, Veli

// Regular function
function sayHello(name) {
  return 'Hello, ' + name;
}
console.log(sayHello('Veli')); // Hello, Veli

