content.text:
Методы объектов определяются как функции внутри объектного литерала. Синтаксис:
```javascript
const object = {
  methodName: function() {
    return result;
  }
};
```
Альтернативно, в ES6 используется более короткий синтаксис:
```javascript
const object = {
  methodName() {
    return result;
  }
};
```
Методы могут обращаться к свойствам объекта с помощью ключевого слова `this`.

content.code:
// Определение метода объекта
const car = {
  brand: 'Honda',
  model: 'Civic',
  year: 2021,
  startEngine: function() {
    return this.brand + ' ' + this.model + ' двигатель запущен!';
  },
  // Короткий синтаксис ES6
  getInfo() {
    return 'Автомобиль: ' + this.brand + ', Год: ' + this.year;
  }
};

console.log(car.startEngine()); // Honda Civic двигатель запущен!
console.log(car.getInfo()); // Автомобиль: Honda, Год: 2021

// Использование `this`
const person = {
  name: 'Айсу',
  age: 22,
  introduce: function() {
    return 'Привет, я ' + this.name + ', мне ' + this.age + ' лет.';
  }
};
console.log(person.introduce()); // Привет, я Айсу, мне 22 лет.

content.text:
Методы можно добавлять к объекту после его создания, как и свойства. Синтаксис:
```javascript
object.newMethod = function() {
  return result;
};
```

content.code:
// Добавление метода
const book = {
  title: 'Основы JavaScript',
  pages: 200
};

// Добавление нового метода
book.getSummary = function() {
  return this.title + ' содержит ' + this.pages + ' страниц.';
};
console.log(book.getSummary()); // Основы JavaScript содержит 200 страниц.

// Пример с ошибкой
const student = {
  name: 'Али',
  grade: 90,
  showGrade: function() {
    return this.name + ' получил ' + this.grade;
  }
};

// Ошибка: Метод вызван в неправильном контексте
const func = student.showGrade;
console.log(func()); // TypeError: Cannot read property 'name' of undefined

// Правильный подход
console.log(student.showGrade()); // Али получил 90

// Ошибка: Неправильное имя метода
console.log(student.showGrades); // undefined (showGrades не существует)

// Сравнение метода и функции
const person = {
  name: 'Вали',
  greet: function() {
    return 'Привет, ' + this.name;
  }
};

// Вызов метода
console.log(person.greet()); // Привет, Вали

// Обычная функция
function sayHello(name) {
  return 'Привет, ' + name;
}
console.log(sayHello('Вали')); // Привет, Вали

